博主您好, 我在项目中使用了您的该轮子, 高度适配有问题, 是每个cell都需要重新tagTextCollectionView控件吗? 下面是我的代码: 

class ArchivesCustomTagTabCell: UITableViewCell {

    override init(style: UITableViewCell.CellStyle, reuseIdentifier: String?) {
        super.init(style: style, reuseIdentifier: reuseIdentifier)
        self.selectionStyle = .none
        self.backgroundColor = .background1
        contentView.backgroundColor = .background1
        setBaseUI()
    }

    var titles: [String]? {
        didSet {
            tagView.removeAllTags()
            titles?.forEach({ value in
                let content = TTGTextTagStringContent.init(text: value)
                content.textColor = UIColor.black1
                content.textFont = UIFont.pf_Regular_16!

                let normalStyle = TTGTextTagStyle.init()
                normalStyle.backgroundColor = UIColor.gray5
                normalStyle.shadowColor = .clear
                normalStyle.borderColor = .clear
                normalStyle.extraSpace = CGSize.init(width: 20, height: 15)

                let selectedStyle = TTGTextTagStyle.init()
                selectedStyle.backgroundColor = UIColor.blue1_b
                selectedStyle.shadowColor = .clear
                selectedStyle.borderColor = .clear
                selectedStyle.extraSpace = CGSize.init(width: 20, height: 15)

                let tag = TTGTextTag.init()
                tag.content = content
                tag.style = normalStyle
                tag.selectedStyle = selectedStyle
                tagView.addTag(tag)
            })
            tagView.reload()
            self.layoutIfNeeded()
        }
    }

    func setBaseUI() {
        contentView.addSubview(tagView)
        tagView.snp.makeConstraints { make in
            make.top.equalToSuperview().offset(KPadding)
            make.left.equalToSuperview().offset(KREctmar)
            make.right.equalToSuperview().offset(-KREctmar)
            make.bottom.equalToSuperview().offset(-KPadding)
        }
    }

    var tagView: TTGTextTagCollectionView = {
        let view = TTGTextTagCollectionView()
        view.preferredMaxLayoutWidth = KScreen_Width - KREctmar * 2
        return view
    }()

    required init?(coder: NSCoder) {
        fatalError("error")
    }

    override func systemLayoutSizeFitting(_ targetSize: CGSize,
                                       withHorizontalFittingPriority horizontalFittingPriority: UILayoutPriority,
                                       verticalFittingPriority: UILayoutPriority) -> CGSize {
        let size = super.systemLayoutSizeFitting(targetSize,
                                               withHorizontalFittingPriority: horizontalFittingPriority,
                                               verticalFittingPriority: verticalFittingPriority)
        return CGSize(width: size.width, height: max(size.height, tagView.intrinsicContentSize.height))
    }
}

